"""Инициализация модуля llm_models_registry: подготовка и слияние реестра."""from __future__ import annotationsfrom pathlib import Pathfrom .boot import LLMModelStoreMergerfrom .module import ModuleConfig, ModuleConfigStoredef module_llm_model_registry_boot(    source_llm_models_store_file: Path | str,    user_llm_models_store_file: Path | str,) -> None:    """    Создаёт при необходимости каталог для user_llm_models_store_file и файл реестра (dict[key, record]).    source_llm_models_store_file — путь к эталонному файлу реестра (источник).    user_llm_models_store_file — путь к целевому файлу реестра (куда писать).    Если файл уже существует: добавляем модели из source, которых нет в target;    обновляем запись только если target ещё разрешает служебную перезапись    (target.can_update=true). После ручного редактирования пользователя запись    должна иметь can_update=false и bootstrap её не трогает.    """    source_file = Path(source_llm_models_store_file).resolve()    user_file = Path(user_llm_models_store_file).resolve()    user_file.parent.mkdir(parents=True, exist_ok=True)    config = ModuleConfig(models_store_file=user_file)    ModuleConfigStore.set(config)    LLMModelStoreMerger.apply_boot_merge(source_file, user_file)__all__ = ["module_llm_model_registry_boot"]